let newOpps = []; try { newOpps = $('New Opportunities').all().map(i => i.json).filter(i => i.opp_title); } catch(e) {}
let deadlines = []; try { deadlines = $('Deadline Alerts').all().map(i => i.json).filter(i => i.opp_title); } catch(e) {}
let intel = []; try { intel = $('Intel Feed Highlights').all().map(i => i.json).filter(i => i.title); } catch(e) {}
let pipeline = {}; try { pipeline = $('Pipeline Health').first().json; } catch(e) { pipeline = {total_plans: 0, active_plans: 0, stale_plans: 0}; }

const today = new Date().toLocaleDateString('en-US', {weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'});

const prompt = `You are GDA Command's Morning Intelligence Briefer. Generate a structured daily intelligence briefing for ${today}.

DATA INPUTS:

1. NEW/UPDATED OPPORTUNITIES (last 24h, score >= 40):
${newOpps.length > 0 ? newOpps.map(o => `- ${o.opp_title} | ${o.agency} | Score: ${o.gda_score} (${o.gda_label}) | NAICS: ${o.naics_code} | Deadline: ${o.response_deadline || 'TBD'} | Value: $${(o.estimated_value || 0).toLocaleString()}`).join('\n') : 'No new opportunities in last 24h'}

2. UPCOMING DEADLINES (next 14 days):
${deadlines.length > 0 ? deadlines.map(d => `- ${d.opp_title} | ${d.agency} | Score: ${d.gda_score} | Due: ${d.response_deadline} (${Math.round(d.days_left)} days)`).join('\n') : 'No deadlines in next 14 days'}

3. INTELLIGENCE FEED (last 24h):
${intel.length > 0 ? intel.map(i => `- [${i.category}] ${i.title} (Score: ${i.relevance_score}) - ${i.body_preview || ''}`).join('\n') : 'No intel feed items in last 24h'}

4. PIPELINE HEALTH:
- Total Capture Plans: ${pipeline.total_plans || 0}
- Active (updated <7 days): ${pipeline.active_plans || 0}
- Stale (>30 days): ${pipeline.stale_plans || 0}

RESPOND WITH JSON ONLY:
{
  "date": "${today}",
  "executive_summary": "2-3 sentence overview of today's key takeaways",
  "priority_actions": [{"action": "...", "urgency": "HIGH/MEDIUM/LOW", "owner": "BD Team", "deadline": "..."}],
  "new_opportunities_summary": "Brief narrative on new opps",
  "top_opportunities": [{"title": "...", "agency": "...", "score": 0, "why": "..."}],
  "deadline_warnings": [{"title": "...", "days_left": 0, "action_needed": "..."}],
  "intel_highlights": [{"headline": "...", "significance": "..."}],
  "pipeline_assessment": "Brief health assessment",
  "market_signals": ["..."],
  "recommended_focus": "What to prioritize today"
}`;

return [{json: {prompt, stats: {new_opps: newOpps.length, deadlines: deadlines.length, intel_items: intel.length, pipeline}}}];

const raw = $input.first().json;
const stats = $('Build Brief Prompt').first().json.stats;
let text = '';
if (raw.content && Array.isArray(raw.content)) text = raw.content.map(c => c.text || '').join('');
else text = JSON.stringify(raw);

let brief = {};
try {
  const clean = text.replace(/```json/g,'').replace(/```/g,'').trim();
  brief = JSON.parse(clean);
} catch(e) {
  const m = text.match(/\{[\s\S]*\}/);
  if (m) try { brief = JSON.parse(m[0]); } catch(e2) { brief = {error: 'Parse failed', raw_text: text.substring(0, 500)}; }
}

return [{json: {
  status: 'ok',
  brief: brief,
  stats: stats,
  generated_at: new Date().toISOString(),
  brief_json: JSON.stringify(brief)
}}];

